import React from "react";
import OneScreen from "./OneScreen";

const RenderUI = ({ data, elements, stageElements, cntrData }) => {
  try {
debugger;
  return (
    <>
      {data.map((item) => {
        switch (item.typ) {
          case "div":
            return (
              <>
                <div className={`${item.cls}`}>
                  {item.child && item.child.length > 0 && (
                    <RenderUI
                      data={item.child}
                      elements={elements}
                      stageElements={stageElements}
                      cntrData={cntrData}
                    />
                  )}
                </div>
              </>
            );

          case "h":
            return (
              <>
                <item.tag className={`${item.cls}`}>{item.val}</item.tag>

                {item.child && item.child.length > 0 && (
                  <RenderUI
                    data={item.child}
                    elements={elements}
                    stageElements={stageElements}
                    cntrData={cntrData}
                  />
                )}
              </>
            );

          case "tab":
            return (
              <>
                <ul
                  className="nav nav-tabs nav-tabs-bordered"
                  id="borderedTab"
                  role="tablist"
                >
                  {item.tabs.map((x) => (
                    <li key={x.id} className="nav-item" role="presentation">
                      <button
                        className={`nav-link ${x.cls}`}
                        id={x.id}
                        data-bs-toggle="tab"
                        data-bs-target={`#${item.tabcontent.find((element) => element.tid === x.id).id}`}
                        type="button"
                        role="tab"
                        aria-controls="home"
                        aria-selected="true"
                      >
                        {x.val}
                      </button>
                    </li>
                  ))}
                </ul>
                <div className="tab-content pt-2" id="borderedTabContent">
                  {item.tabcontent.map((y) => (
                    <div
                      className= {`tab-pane fade ${y.cls}`} 
                      id={y.id}
                      key={y.id}
                      role="tabpanel"
                      aria-labelledby={y.tid}
                    >
                      <div className="row">
                      {y.child && y.child.length > 0 && (
                        <RenderUI
                          data={y.child}
                          elements={elements}
                          stageElements={stageElements}
                          cntrData={cntrData}
                        />
                      )}
                      </div>
                    </div>
                  ))}
                </div>
              </>
            );

          case "input":
            return (
              <>
                <OneScreen
                  dataprops={
                    elements.find((element) => element.fieldname === item.id)
                      .elementdata
                  }
                  key={item.id}
                  fieldname={item.id}
                  stagelementdata={stageElements}
                  elementdefs={cntrData}
                  cls={item.cls}
                  childUI = {item.child}
                />
              </>
            );

            case "grid":
              return (
                <>
                  <OneScreen
                    dataprops={
                      elements.find((element) => element.fieldname === item.id)
                        .elementdata
                    }
                    key={item.id}
                    fieldname={item.id}
                    stagelementdata={stageElements}
                    elementdefs={cntrData}
                    cls={item.cls}
                    childUI = {item.child}
                  />
                </>
              );

          default:
            return null;
        }
      })}
    </>
    
  );
}
catch(e){

  console.log("Error in Render UI -", e)
}
  
};

export default RenderUI;
