import React  from "react";
import Timeline from "../../htmlcomponents/Timeline";
import { FormContext } from "../Contexts/FormContext";
import { useContext } from "react";

export const Sidepanel = () => {


  const fieldname = "cmbAction";

  const {
    register,
    getValues,
    setValue,
    combodata,
    setComboData,
    elements,
    eDefHldr,
    actionHighlight,
    formState: { errors }
  } = useContext(FormContext);

  debugger;
  const options =  combodata["sta"] && Object.keys(combodata["sta"]).length > 0  ? combodata["sta"] : [];

  return (
    <>
      <ul
        className="nav nav-pills mb-3 shadow-sm"
        id="pills-tab"
        role="tablist"
      >
        <li className="nav-item">
          <a
            className="nav-link active"
            id="pills-home-tab"
            data-bs-toggle="tab"
            data-bs-target="#pills-home"
            href="#pills-home"
            role="tab"
            aria-controls="pills-home"
            aria-selected="true"
          >
            Action
          </a>
        </li>
        <li className="nav-item">
          <a
            className="nav-link"
            id="pills-profile-tab"
            data-bs-toggle="tab"
            data-bs-target="#pills-profile"
            href="#pills-profile"
            role="tab"
            aria-controls="pills-profile"
            aria-selected="false"
          >
            Timeline
          </a>
        </li>
        <li className="nav-item">
          <a
            className="nav-link"
            id="pills-contact-tab"
            data-bs-toggle="tab"
            data-bs-target="#pills-contact"
            href="#pills-contact"
            role="tab"
            aria-controls="pills-contact"
            aria-selected="false"
          >
            Comments
          </a>
        </li>
      </ul>

      <div className="tab-content container" id="pills-tabContent p-3">
        <div
          className="tab-pane fade show active"
          id="pills-home"
          role="tabpanel"
          aria-labelledby="pills-home-tab"
        >


          <select 
        className={`${actionHighlight} form-select`}
        aria-label="Default select example"
        style={{ cursor: "pointer" }} 
        disabled= {false} //{eDefHldr.stg.prp[fieldname].ro}
        {...register(fieldname, {
          
          // onChange: () => showDescription(),
        })}
      >
        <option key="0" value="">
          --Select Action--
        </option>
        {options.map((item) => (
          <option key={item.k} value={item.k}>
            {item.v}
          </option>
        ))}
      </select>

            
          <div className="content">No actions available</div>
        </div>
        <div
          className="tab-pane fade"
          id="pills-profile"
          role="tabpanel"
          aria-labelledby="pills-profile-tab"
        >
          <Timeline></Timeline>
        </div>
        <div
          className="tab-pane fade third"
          id="pills-contact"
          role="tabpanel"
          aria-labelledby="pills-contact-tab"
        >
          <div className="form-group addinfo">
            <textarea
              className="form-control"
              id="exampleFormControlTextarea1"
              rows="3"
            ></textarea>
          </div>
        </div>
      </div>
    </>
  );
};
