import React, { useContext } from "react";
import { FormContext } from "../Contexts/FormContext";
import { EventCaller } from "../BusinessLogics/EventHandler";

export const DateBox = ({ eid, fieldname, cap, col, mn, ev, val, mxLen }) => {
  const { register, getValues, setValue } = useContext(FormContext);


  let clientevent ={}
  if (ev) {
    clientevent = JSON.parse(ev.change);
  }
  return (
    <div className={`${col} mb-3`}>
      <label
        htmlFor={fieldname}
        className={`${mn ? "required" : ""} form-label`}
      >
        {cap}
      </label>
      <input
        name={fieldname}
        type="date"
        className="form-control"
        {...register(fieldname, {
          required: mn,
          value: val,
          onBlur: () =>
            EventCaller(
              clientevent.fn,
              fieldname,
              clientevent.outel,
              getValues,
              setValue
            ),
        })}
      />
    </div>
  );
};

export default DateBox;
